    let evil_key = "'; DROP TABLE facts; --";
    mgr.store_fact(evil_key, "sentinel").unwrap();
    let facts = mgr.retrieve_all_facts().unwrap();
    assert_eq!(facts.len(), 1);  // Table survived
    assert_eq!(facts[0].key, evil_key);  // Stored literally
}

#[test]
fn test_p0_sql_injection_project_isolation() {
    // Project name = "x' OR '1'='1" should NOT see other projects
    let evil_project = "x' OR '1'='1";
    let mgr_evil = MemoryManager::open(&db_path, evil_project, None).unwrap();
    let facts = mgr_evil.retrieve_all_facts().unwrap();
    for f in &facts {
        assert_ne!(f.value, "sensitive-value");
