use anyhow::{Context, Result};
use serde::Deserialize;
use std::path::Path;

#[derive(Debug, Clone, Deserialize)]
pub struct PluginManifest {
    pub plugin: PluginMeta,
    #[serde(default)]
    pub tools: Vec<PluginToolDef>,
    #[serde(default)]
    pub skills: Vec<PluginSkillDef>,
    #[serde(default)]
    pub hooks: Vec<PluginHookDef>,
}

#[derive(Debug, Clone, Deserialize)]
pub struct PluginMeta {
    pub name: String,
    pub version: String,
    #[serde(default)]
    pub description: String,
}

#[derive(Debug, Clone, Deserialize)]
pub struct PluginToolDef {
    pub name: String,
    pub description: String,
    pub command: String,
    #[serde(default = "default_params")]
    pub params: serde_json::Value,
}

fn default_params() -> serde_json::Value {
    serde_json::json!({"type": "object", "properties": {}})
}

/// Cross-platform path escape detection.
fn is_path_escape(path: &str) -> bool {
    if path.contains("..") { return true; }           // traversal
    if path.starts_with('/') { return true; }           // Unix absolute
    if path.contains("..\\") { return true; }          // Windows backslash traversal
    if path.len() >= 2 && path.as_bytes()[0].is_ascii_alphabetic()
        && path.as_bytes()[1] == b':' { return true; }  // C:\... or D:/...
    if path.starts_with("\\\\") { return true; }       // UNC \\server\share
    false
}

pub fn load_manifest(plugin_dir: &Path) -> Result<PluginManifest> {
    let manifest_path = plugin_dir.join("plugin.toml");
    let content = std::fs::read_to_string(&manifest_path)
        .with_context(|| format!("Failed to read {}", manifest_path.display()))?;
    let manifest: PluginManifest = toml::from_str(&content)
        .with_context(|| format!("Failed to parse {}", manifest_path.display()))?;

    // Validate plugin name: alphanumeric + hyphens only
    if !manifest.plugin.name.chars().all(|c| c.is_alphanumeric() || c == '-' || c == '_') {
        anyhow::bail!("Invalid plugin name '{}'", manifest.plugin.name);
    }

    // Validate all command/file paths are relative and don't escape
    for tool in &manifest.tools {
        if is_path_escape(&tool.command) {
            anyhow::bail!("Tool command '{}' must be relative to plugin dir", tool.command);
        }
    }
    for hook in &manifest.hooks {
        if is_path_escape(&hook.command) {
            anyhow::bail!("Hook command '{}' must be relative to plugin dir", hook.command);
        }
    }
    for skill in &manifest.skills {
        if is_path_escape(&skill.file) {
            anyhow::bail!("Skill file '{}' must be relative to plugin dir", skill.file);
        }
    }

    Ok(manifest)
}
```

The `is_path_escape` function blocks five attack vectors: Unix traversal (`..`), Unix absolute (`/usr/bin/rm`), Windows backslash traversal (`..\..\`), Windows drive letters (`C:\`), and UNC paths (`\\server\share`). All checked on every platform because a manifest could be authored on Windows and loaded on Unix.

```rust
pub fn eval_to_bool(expr: &Expression, ctx: &EvalContext) -> bool {
    match expr {
        Expression::BoolLit(b) => *b,
        Expression::Not(inner) => !eval_to_bool(inner, ctx),
        Expression::BinOp { left, op, right } => match op {
            BinOperator::And => eval_to_bool(left, ctx) && eval_to_bool(right, ctx),
            BinOperator::Or => eval_to_bool(left, ctx) || eval_to_bool(right, ctx),
            BinOperator::Eq => eval_to_string(left, ctx) == eval_to_string(right, ctx),
            BinOperator::Neq => eval_to_string(left, ctx) != eval_to_string(right, ctx),
        },
        Expression::Call { name, args } => eval_builtin_bool(name, args, ctx),
        Expression::Ident(name) => match ctx.variables.get(name.as_str()) {
            Some(EvalValue::Bool(b)) => *b,
            Some(EvalValue::String(s)) => !s.is_empty(),
            _ => false,
        },
        Expression::InExpr { value, list } => {
            let val = eval_to_string(value, ctx);
            match list.as_ref() {
                Expression::List(items) => items.iter().any(|i| eval_to_string(i, ctx) == val),
                Expression::Ident(name) => match ctx.variables.get(name.as_str()) {
                    Some(EvalValue::List(items)) => items.iter().any(|s| *s == val),
                    _ => false,
                },
                _ => false,
            }
        }
        _ => false,
    }
}

fn eval_builtin_bool(name: &str, args: &[Expression], ctx: &EvalContext) -> bool {
    match name {
        "contains" => {
            let haystack = args.first().map(|a| eval_to_string(a, ctx)).unwrap_or_default();
            let needle = args.get(1).map(|a| eval_to_string(a, ctx)).unwrap_or_default();
            haystack.contains(&needle)
        }
        "matches" => {
            let text = args.first().map(|a| eval_to_string(a, ctx)).unwrap_or_default();
            let pattern = args.get(1).map(|a| eval_to_string(a, ctx)).unwrap_or_default();
            regex::Regex::new(&pattern).map(|r| r.is_match(&text)).unwrap_or(false)
        }
        "files_match" => {
            let pattern = args.first().map(|a| eval_to_string(a, ctx)).unwrap_or_default();
            let files = match ctx.variables.get("staged_files") {
                Some(EvalValue::List(list)) => list.clone(),
                _ => vec![],
            };
            files.iter().any(|f| glob::Pattern::new(&pattern).map(|p| p.matches(f)).unwrap_or(false))
        }
        _ => false,
    }
}
```

