```rust
pub struct HardwareInfo {
    pub arch: CpuArch,
    pub gpu: GpuType,
    pub ram_gb: u64,
}

impl HardwareInfo {
    pub fn detect() -> Self {
        let arch = if cfg!(target_arch = "aarch64") && cfg!(target_os = "macos") {
            CpuArch::AppleSilicon
        } else if cfg!(target_arch = "x86_64") {
            CpuArch::X86_64
        } else {
            CpuArch::Other(std::env::consts::ARCH.to_string())
        };

        let gpu = if cfg!(target_os = "macos") && arch == CpuArch::AppleSilicon {
            GpuType::Metal
        } else {
            GpuType::None // TODO: CUDA detection via nvidia-smi
        };

        let ram_gb = Self::detect_ram_gb();
        Self { arch, gpu, ram_gb }
    }

    #[cfg(target_os = "macos")]
    fn detect_ram_gb() -> u64 {
        Command::new("sysctl").arg("-n").arg("hw.memsize")
            .output().ok()
            .and_then(|out| String::from_utf8_lossy(&out.stdout).trim().parse::<u64>().ok())
            .map(|bytes| bytes / (1024 * 1024 * 1024))
            .unwrap_or(8)
    }
}
```

